type anon_anon_2 (discr : unsigned := 0) is record
   case discr is
      when 0 =>
         boolean : aliased amqp_boolean_t;
      when 1 =>
         i8 : aliased Integer_8;
      when 2 =>
         u8 : aliased Unsigned_8;
      when 3 =>
         i16 : aliased Integer_16;
      when 4 =>
         u16 : aliased Unsigned_16;
      when 5 =>
         i32 : aliased Integer_32;
      when 6 =>
         u32 : aliased Unsigned_32;
      when 7 =>
         i64 : aliased Integer_64;
      when 8 =>
         u64 : aliased Unsigned_64;
      when 9 =>
         f32 : aliased float;
      when 10 =>
         f64 : aliased double;
      when 11 =>
         decimal : aliased amqp_decimal_t;
      when 12 =>
         bytes : aliased amqp_bytes_t;
      when 13 =>
         table : aliased amqp_table_t;
      when others =>
         c_array : aliased amqp_array_t;
   end case;
end record;

type anon_anon_4 (discr : unsigned := 0) is record
   case discr is
      when 0 =>
         method : aliased amqp_method_t;
      when 1 =>
         properties : aliased anon_anon_5;
      when 2 =>
         body_fragment : aliased amqp_bytes_t;
      when others =>
         protocol_header : aliased anon_anon_6;
   end case;
end record;

type anon_anon_5 is record
   class_id : aliased Unsigned_16;
   body_size : aliased Unsigned_64;
   decoded : System.Address;
   raw : aliased amqp_bytes_t;
end record;

